/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const n = nums.length;

    // 1. Precompute closest(x)
    const closest = new Array(n);
    for (let x = 0; x < n; x++) {
        let minDiff = Infinity;
        let bestY = -1;

        // Check neighbors y = x-1 and y = x+1
        const potentialYs = [];
        if (x > 0) potentialYs.push(x - 1);
        if (x < n - 1) potentialYs.push(x + 1);

        for (const y of potentialYs) {
            const diff = Math.abs(nums[x] - nums[y]);

            // The problem states: "if two adjacent indices have the same difference, choose the smaller index."
            if (diff < minDiff) {
                minDiff = diff;
                bestY = y;
            } else if (diff === minDiff) {
                if (y < bestY || bestY === -1) {
                    bestY = y;
                }
            }
        }
        closest[x] = bestY;
    }

    // 2. Precompute shortest path distances using Dynamic Programming / All-Pairs Shortest Path style thinking,
    // but since movements are directed (or bidirectional cost is known), we can use Dijkstra-like ideas or simplified DP.

    // Since we are looking for min cost path from l to r, and the graph structure is based on index proximity
    // and cost structure, this is a Shortest Path problem on a graph with N nodes.
    // N is up to 10^5, so N^2 algorithms are too slow. Dijkstra's O(E log V) is needed.
    // V = N. E = N (for closest moves) + N*(N-1) (for direct moves).
    // The direct move (x -> y) has cost |nums[x] - nums[y]|, which is O(N^2) edges. This is the killer.

    // Re-evaluating the movement:
    // From x, we can go to:
    // 1. Any y: Cost |nums[x] - nums[y]|. (N-1 edges)
    // 2. closest(x): Cost 1. (1 edge)

    // If we use the direct move (1), we can reach ANY node in one step.
    // The minimum cost to go from l to r must be min( |nums[l] - nums[r]|, min_path_via_closest ).

    // Path options from l to r:
    // 1. Direct jump: Cost |nums[l] - nums[r]|
    // 2. Use closest moves: l -> c1 -> c2 -> ... -> r

    // If we use the direct jump (1) from *any* node x, the cost is determined entirely by the values.
    // If we use the closest move (2), the cost is 1.

    // Let d[i][j] be the minimum cost from i to j.
    // d[i][j] = min( |nums[i] - nums[j]|, Cost_via_closest(i, j) )

    // If we take the direct jump from L to R, cost is |nums[L] - nums[R]|. This is an upper bound.

    // If we use the closest moves, the path only involves the 'closest' edges (cost 1).
    // This forms a graph where edges are (x, closest(x)) and (closest(x), x) with weight 1.
    // Since the graph is undirected (if we consider the cost 1 move symmetric, which it is for path finding),
    // the shortest path using only cost-1 moves is just the minimum number of steps in the closest-move graph.

    // Let dist_closest[i][j] be the minimum number of steps from i to j using only closest moves.
    // We can compute this using BFS starting from each node, but N=10^5 means O(N^2) BFS is too slow.

    // Since the closest moves are local (only adjacent indices, perhaps one step away), the resulting graph is sparse.
    // The graph is defined by edges (x, closest(x)) and (closest(x), x), both weight 1.
    // We can use BFS to find the shortest path in this graph. We need all-pairs shortest path, but only for the paths that are potentially shorter than the direct jump.

    // Let's check the structure of the closest move graph. It is a collection of paths/cycles of length 2 (since closest(x) is usually x-1 or x+1).
    // The graph is effectively just the set of indices $\{0, 1, \dots, N-1\}$ with edges $(x, \text{closest}(x))$ and $(\text{closest}(x), x)$ all having weight 1.

    // Since the closest neighbor is always adjacent (x-1 or x+1), the graph formed by closest moves is essentially the line graph of indices, where some edges might be skipped if the closest neighbor is further away, but since it's always a neighbor, it's a subgraph of the path graph 0-1-...-(N-1).

    // Wait, closest(x) is defined as the *adjacent* index y that minimizes abs(nums[x]-nums[y]).
    // For any x, closest(x) must be x-1 or x+1 (if they exist).
    // This means the graph formed by closest moves is a subgraph of the path graph (0-1-...-(N-1)).
    // The shortest path between any two nodes i and j in this graph is simply |i - j|. (Assuming all adjacent moves are possible, which they are if closest(x) is x-1 or x+1).

    // Let's confirm:
    // If closest(x) = x-1, then x-1 <-> x is an edge of weight 1.
    // If closest(x) = x+1, then x <-> x+1 is an edge of weight 1.
    // Since for any x, at least one neighbor (x-1 or x+1) is chosen, the graph connecting all nodes using only these "closest" edges must span all nodes 0 to N-1 because it includes a subset of all adjacent edges.
    // If the graph spans all nodes 0..N-1, the shortest path distance using only these edges is the minimum number of steps, which is the Manhattan distance |i-j| if all edges (i, i+1) exist.

    // Since the set of edges includes at least one edge incident to every node, and the underlying structure is linear, the shortest path between i and j using only these edges is indeed |i-j|.

    // Therefore, Cost_via_closest(l, r) = |l - r|.

    // The total minimum cost for a query [l, r] is:
    // MinCost = min( |nums[l] - nums[r]|, |l - r| )

    const ans = [];
    for (const [l, r] of queries) {
        // Option 1: Direct jump from l to r
        const costDirect = Math.abs(nums[l] - nums[r]);

        // Option 2: Using only closest moves (which takes |l-r| steps, each costing 1)
        const costClosest = Math.abs(l - r);

        const minCost = Math.min(costDirect, costClosest);
        ans.push(minCost);
    }

    return ans;
}

