 * @return {std::vector<long long>}
 */
std::vector<long long> solve(std::vector<long long> nums, std::vector<std::vector<long long>> queries) {
    int n = nums.size();

    // Based on the analysis:
    // 1. The direct jump from x to y costs abs(nums[x] - nums[y]).
    // 2. The closest move from x to closest(x) costs 1.
    // Since closest(x) must be an adjacent index (x-1 or x+1), the graph formed by only using closest moves
    // is a subgraph of the path graph 0-1-...-(N-1). Because the structure is linear, the shortest path
    // distance between any two indices l and r using only these moves is simply |l - r| steps, each costing 1.
    // Cost_via_closest(l, r) = |l - r|.

    // The minimum cost to go from l to r is the minimum of:
    // a) The direct jump cost: abs(nums[l] - nums[r])
    // b) The cost using only closest moves: |l - r|

    std::vector<long long> ans;
    for (const auto& query : queries) {
        long long l = query[0];
        long long r = query[1];

        // Option 1: Direct jump from l to r
        long long costDirect = std::abs(nums[l] - nums[r]);

        // Option 2: Using only closest moves
        // Since the shortest path in the closest-move graph is |l - r| steps of cost 1 each.
        long long costClosest = std::abs(l - r);

        long long minCost = std::min(costDirect, costClosest);
        ans.push_back(minCost);
    }

    return ans;
}
